 <body>
    <!-- social  -->
    <section class="social">
      <div class="container text-center">
        <ul>
          <li>
            <a href="#"><img
                src="data:image/png;base64,"
                alt="facebook-new" /></a>
          </li>
          <a href="#"><img
              src="data:image/png;base64,"
              alt="instagram-new--v1" /></a>
          <a href="#"><img
